import heapq

class Solution(object):
    def clearStars(self, s):
        # For each '*', remove it and the smallest (rightmost if tie) char to its left.
        # Use 26 stacks (one per char), track which indices are deleted.
        stacks = [[] for _ in range(26)]
        deleted = [False] * len(s)
        for i, c in enumerate(s):
            if c == '*':
                deleted[i] = True
                # Find smallest char available
                for ch in range(26):
                    if stacks[ch]:
                        j = stacks[ch].pop()
                        deleted[j] = True
                        break
            else:
                stacks[ord(c) - ord('a')].append(i)
        return ''.join(s[i] for i in range(len(s)) if not deleted[i])
